#include <bits/stdc++.h>
using namespace std;

const int N=1010,S=1e4+10,mod=1e9+7;

inline void cmin(int &x,int y){
    x=min(x,y);
}

inline void add(int &x,long long y){
	x=(x+y)%mod;
}

struct Node{
    int g[3][3];
    inline void init(){
        for(int i=0;i<3;i++)
        	for(int j=0;j<3;j++)
        		g[i][j]=101;
//        memset(g,0x3f,sizeof(g));
    }
    inline bool operator<(Node x)const{
        for(int i=0;i<3;i++)
            for(int j=0;j<3;j++)
                if(g[i][j]!=x.g[i][j])
                    return g[i][j]<x.g[i][j];
        return 0;
    }
    inline Node operator+(int a){
        Node res;
        res.init();
        for(int i=0;i<3;i++)
            for(int j=0;j<3;j++){
				if(g[i][j]>100)
					continue;
                for(int p=0;p<=min(2-j,i);p++)
                    for(int m=0;m<3;m++){
                        if(a-i-j-m<0) cmin(res.g[p+j][m],g[i][j]-(a-i-j-m));
                        else if(a-i-j-m==1) cmin(res.g[p+j][m],g[i][j]+1);
                        else cmin(res.g[p+j][m],g[i][j]);
                    }
            }
        return res;
    }
}t[S];

int nxt[S][7],tot,f[N][S];
int T,n,k,l[N],r[N];
map<Node,int> mp;

void build(){
    tot++;
    t[tot].init();
    t[tot].g[0][0]=0;
    mp[t[tot]]=tot;
    tot++;
    t[tot].init();
    mp[t[tot]]=tot;
    for(int x=1;x<=tot;x++){
    	/*
    	printf("%d\n",x);
    	for(int i=0;i<5;i++){
    		for(int j=0;j<3;j++)
    			printf("%d ",min(101,t[x].g[i][j]));
    		puts("");
		}
		*/
        for(int i=0;i<7;i++){
            Node tmp=t[x]+i;
            if(!mp.count(tmp)){
                t[++tot]=tmp;
                mp[tmp]=tot;
            }
            nxt[x][i]=mp[tmp];
            //printf("%d ",nxt[x][i]);
        }
        //puts("");
    }
//    printf("%d",tot);
}

int main(){
	// freopen("qwq.in","r",stdin); 
    build();
    scanf("%d",&T);
    while(T--){
    	bool flag=true;
    	scanf("%d%d",&n,&k);
    	for(int i=1;i<=n;i++){
       		scanf("%d%d",&l[i],&r[i]);
			// l[i]=0,r[i]=1e9; 
    		if(l[i])
    			flag=false;
    	}
    	for(int i=0;i<=n;i++)
    		for(int j=1;j<=tot;j++)
    			f[i][j]=0;
    	f[0][1]=1;
    	for(int i=1;i<=n;i++)
    		for(int j=1;j<=tot;j++){
    			if(!f[i-1][j]) continue;
    			for(int k=l[i];k<=min(5,r[i]);k++)
    				add(f[i][nxt[j][k]],f[i-1][j]);
    			if(6<=r[i])
    				add(f[i][nxt[j][6]],1ll*(r[i]-max(l[i]-1,5))*f[i-1][j]);
			}
		int ans=0;
		for(int i=1;i<=tot;i++)
			if(t[i].g[0][0]<=k)
				add(ans,f[n][i]);
		if(k==1){
			if(flag) add(ans,mod-1);
			if(n==3 && l[1]<=1 && 1<=r[1] && l[2]<=1 && 1<=r[2] && l[3]<=1 && 1<=r[3]) add(ans,mod-1);
		}
		printf("%d\n",ans);
	}
    return 0;
}
